const MONSTER_MOVE_JITTER_RATIO = 0.18;
const ZONE_RING_ONE_DELAY_MS = 900;
const ZONE_RING_TWO_DELAY_MS = 2200;
const WORLD_MONSTER_SWEEP_ZONES_PER_CYCLE = 3;
const WORLD_MONSTER_SWEEP_MAX_ACTIONS_PER_CYCLE = 12;
const WORLD_MONSTER_STUCK_RECOVERY_MULTIPLIER = 6;
const MONSTER_RECENT_POSITIONS_LIMIT = 6;

// Monster movement intervals by type (in milliseconds).
// Shorter base intervals make the world feel alive, while per-monster jitter
// and a batched scheduler keep large packs from moving all at once.
const MONSTER_MOVE_INTERVALS: Record<number, number> = {
  [KILLING_HUT_ID]: 26000,
  [KIND_SANTA_ID]: 23000,
  [GORYNYCH_ID]: 30000,
  [KOLOBOK_ID]: 28000,
  [BABA_YAGA_ID]: 29000,
  [BRONEKUR_ID]: 18000,
};
const DEFAULT_MONSTER_MOVE_INTERVAL = 32000;
const MONSTER_FATAL_HIT_DELAY_MS = 1200;

function getMonsterMoveSeed(monsterId: string | number, buildingId: number): number {
  const source = `${monsterId}:${buildingId}`;
  let hash = 0;
  for (let i = 0; i < source.length; i++) {
    hash = ((hash << 5) - hash + source.charCodeAt(i)) | 0;
  }
  return Math.abs(hash);
}

function hashMonsterZoneSeed(source: string): number {
  let hash = 0;
  for (let i = 0; i < source.length; i++) {
    hash = ((hash << 5) - hash + source.charCodeAt(i)) | 0;
  }
  return Math.abs(hash);
}

function seededShuffle<T>(items: T[], seedSource: string): T[] {
  const result = [...items];
  let seed = hashMonsterZoneSeed(seedSource) || 1;
  for (let i = result.length - 1; i > 0; i--) {
    seed = (seed * 1664525 + 1013904223) >>> 0;
    const j = seed % (i + 1);
    [result[i], result[j]] = [result[j], result[i]];
  }
  return result;
}

function getMonsterMoveInterval(buildingId: number, monsterId: string | number): number {
  const baseInterval = MONSTER_MOVE_INTERVALS[buildingId] || DEFAULT_MONSTER_MOVE_INTERVAL;
  const seed = getMonsterMoveSeed(monsterId, buildingId) % 1000;
  const jitter = ((seed / 999) * 2 - 1) * MONSTER_MOVE_JITTER_RATIO;
  return Math.max(12000, Math.round(baseInterval * (1 + jitter)));
}

function getPlaybackDurationMs(frameCount: number, fps: number, durationMultiplier = 1): number {
  return frameCount * (1000 / fps) * durationMultiplier;
}

function getPlaybackFrameIndex(elapsedMs: number, frameCount: number, fps: number, durationMultiplier = 1): number {
  const effectiveFps = fps / durationMultiplier;
  return Math.min(Math.floor(elapsedMs / (1000 / effectiveFps)), frameCount - 1);
}

const MONSTER_WALK_ANIM_DURATION = 5000; // 5 seconds of walk animation after each step
const MONSTER_ATTACK_INTERVAL_MS = 40000;
const CANNON_ATTACK_INTERVAL_MS = 40000;
const CANNON_TICK_INTERVAL_MS = 1000;
const MONSTER_AI_TICK_INTERVAL_MS = 250;
const MONSTER_MOVE_BATCH_INTERVAL_MS = 900;
const MAX_MONSTER_MOVES_PER_BATCH = 6;
const MAX_MONSTER_WRITE_UPDATES_PER_TICK = 20;
const MONSTER_WRITE_MIN_INTERVAL_MS = 600;
const MONSTER_WALK_DURATION_MULTIPLIER = 1.5;

type MonsterMoveStep = { x: number; y: number; dx: number; dy: number };
type MonsterDirection = { dx: number; dy: number };
type MonsterPatrolMoveResult = {
    chosenMove: MonsterMoveStep | null;
    selectedTurn: 'preferred' | 'alternate' | 'forward' | 'random' | 'none';
};
type MonsterTeleportSpot = { x: number; y: number; zoneId: string };

function isMonsterAttackTargetCandidate(
    monster: Pick<PlacedBuilding, 'id' | 'ownerId' | 'buildingId' | 'x' | 'y'>,
    target: PlacedBuilding,
    buildingData: Building[],
    options?: {
        blockedTargetIds?: Set<string>;
        pendingDestroyedIds?: Set<string>;
    }
): boolean {
    const targetId = String(target.id);
    const targetInfo = buildingData.find(i => i.id === target.buildingId);
    if (target.ownerId === monster.ownerId) return false;
    if (target.buildingId === RIVER_ID || target.buildingId === MOUNTAIN_ID) return false;
    if (targetInfo?.stats.isMonster) return false;
    if (options?.blockedTargetIds?.has(targetId)) return false;
    if (options?.pendingDestroyedIds?.has(targetId)) return false;
    // Keep helper behavior aligned with the live monster AI:
    // buildings under construction are still valid targets.
    if (target.isDestroying) return false;
    if (target.hp !== undefined && target.hp <= 0) return false;
    return true;
}

function isMonsterHoldTargetCandidate(
    monster: Pick<PlacedBuilding, 'id' | 'ownerId' | 'buildingId' | 'x' | 'y'>,
    target: PlacedBuilding,
    buildingData: Building[],
    options?: {
        blockedTargetIds?: Set<string>;
        pendingDestroyedIds?: Set<string>;
    }
): boolean {
    const targetId = String(target.id);
    const targetInfo = buildingData.find(i => i.id === target.buildingId);
    if (target.ownerId === monster.ownerId) return false;
    if (target.buildingId === RIVER_ID || target.buildingId === MOUNTAIN_ID) return false;
    if (targetInfo?.stats.isMonster) return false;
    if (options?.blockedTargetIds?.has(targetId)) return false;
    if (options?.pendingDestroyedIds?.has(targetId)) return false;
    if (target.hp !== undefined && target.hp <= 0) return false;
    return true;
}

function getMonsterAdjacentAttackTarget(
    monster: Pick<PlacedBuilding, 'id' | 'ownerId' | 'buildingId' | 'x' | 'y'>,
    buildings: PlacedBuilding[],
    buildingData: Building[],
    options?: {
        blockedTargetIds?: Set<string>;
        pendingDestroyedIds?: Set<string>;
        preferredTargetId?: string | null;
        isWrappedWorld?: boolean;
    }
): PlacedBuilding | null {
    const monsterInfo = buildingData.find(i => i.id === monster.buildingId);
    const neighbors = getCardinalNeighborTiles(monster.x, monster.y, !!options?.isWrappedWorld);

    const candidates = buildings.filter(target =>
        neighbors.some(n => n.x === target.x && n.y === target.y) &&
        isMonsterAttackTargetCandidate(monster, target, buildingData, options)
    );
    if (candidates.length === 0) return null;

    const preferredTargetId = options?.preferredTargetId ? String(options.preferredTargetId) : null;
    if (preferredTargetId) {
        const preferredTarget = candidates.find((t) => String(t.id) === preferredTargetId);
        if (preferredTarget) return preferredTarget;
    }

    const hates = monsterInfo?.stats.hates;
    const hatedTarget = candidates.find((t) => {
        const info = buildingData.find(i => i.id === t.buildingId);
        return hates && info?.category === hates;
    });
    return hatedTarget || candidates[0];
}

function getMonsterAdjacentHoldTarget(
    monster: Pick<PlacedBuilding, 'id' | 'ownerId' | 'buildingId' | 'x' | 'y'>,
    buildings: PlacedBuilding[],
    buildingData: Building[],
    options?: {
        blockedTargetIds?: Set<string>;
        pendingDestroyedIds?: Set<string>;
        preferredTargetId?: string | null;
        isWrappedWorld?: boolean;
    }
): PlacedBuilding | null {
    const monsterInfo = buildingData.find(i => i.id === monster.buildingId);
    const neighbors = getCardinalNeighborTiles(monster.x, monster.y, !!options?.isWrappedWorld);

    const candidates = buildings.filter(target =>
        neighbors.some(n => n.x === target.x && n.y === target.y) &&
        isMonsterHoldTargetCandidate(monster, target, buildingData, options)
    );
    if (candidates.length === 0) return null;

    const preferredTargetId = options?.preferredTargetId ? String(options.preferredTargetId) : null;
    if (preferredTargetId) {
        const preferredTarget = candidates.find((t) => String(t.id) === preferredTargetId);
        if (preferredTarget) return preferredTarget;
    }

    const hates = monsterInfo?.stats.hates;
    const hatedTarget = candidates.find((t) => {
        const info = buildingData.find(i => i.id === t.buildingId);
        return hates && info?.category === hates;
    });
    return hatedTarget || candidates[0];
}

function getMonsterChaseTarget(
    monster: Pick<PlacedBuilding, 'id' | 'ownerId' | 'buildingId' | 'x' | 'y'>,
    buildings: PlacedBuilding[],
    buildingData: Building[],
    options?: {
        searchRadius?: number;
        blockedTargetIds?: Set<string>;
        pendingDestroyedIds?: Set<string>;
        isWrappedWorld?: boolean;
    }
): PlacedBuilding | null {
    const monsterInfo = buildingData.find(i => i.id === monster.buildingId);
    const searchRadius = options?.searchRadius ?? (monster.buildingId === BRONEKUR_ID ? 10 : 5);
    let nearestTarget: { id: string; x: number; y: number; dist: number; hated: boolean } | null = null;

    buildings.forEach((target) => {
        if (String(target.id) === String(monster.id)) return;
        if (!isMonsterAttackTargetCandidate(monster, target, buildingData, options)) return;
        const dist = getWrappedManhattanDistance(monster, target, !!options?.isWrappedWorld);
        if (dist > searchRadius) return;
        const targetInfo = buildingData.find(i => i.id === target.buildingId);
        const hated = Boolean(monsterInfo?.stats.hates && targetInfo?.category === monsterInfo.stats.hates);
        if (
            !nearestTarget ||
            (hated && !nearestTarget.hated) ||
            (hated === nearestTarget.hated && dist < nearestTarget.dist)
        ) {
            nearestTarget = { id: String(target.id), x: target.x, y: target.y, dist, hated };
        }
    });

    if (!nearestTarget) return null;
    const target = buildings.find(b => String(b.id) === nearestTarget!.id);
    return target && isBuildingAlive(target) ? target : null;
}

function chooseMonsterMoveTowardTarget(
    validMoves: MonsterMoveStep[],
    target: Pick<PlacedBuilding, 'x' | 'y'>,
    isWrappedWorld: boolean
): MonsterMoveStep | null {
    if (validMoves.length === 0) return null;
    let bestMove = validMoves[0];
    let bestDist = getWrappedManhattanDistance(validMoves[0], target, isWrappedWorld);
    validMoves.forEach(move => {
        const dist = getWrappedManhattanDistance(move, target, isWrappedWorld);
        if (dist < bestDist) {
            bestDist = dist;
            bestMove = move;
        }
    });
    return bestMove;
}

function getMonsterPatrolDirection(monsterId: string | number, buildingId: number): MonsterDirection {
    const seed = getMonsterMoveSeed(monsterId, buildingId);
    const dirs = [
        { dx: 1, dy: 0 },
        { dx: -1, dy: 0 },
        { dx: 0, dy: 1 },
        { dx: 0, dy: -1 }
    ];
    return dirs[seed % dirs.length];
}

function chooseMonsterPatrolMove(
    validMoves: MonsterMoveStep[],
    lastDir: MonsterDirection,
    preferLeftTurn: boolean,
    monsterId: string | number,
    buildingId: number,
    fallbackStepOffset = 0,
    previousPos?: { x: number; y: number }
): MonsterPatrolMoveResult {
    if (validMoves.length === 0) {
        return { chosenMove: null, selectedTurn: 'none' };
    }

    const leftTurn = { dx: -lastDir.dy, dy: lastDir.dx };
    const rightTurn = { dx: lastDir.dy, dy: -lastDir.dx };
    const preferredTurn = preferLeftTurn ? leftTurn : rightTurn;
    const alternateTurn = preferLeftTurn ? rightTurn : leftTurn;
    const preferTurnMove = validMoves.find(m => m.dx === preferredTurn.dx && m.dy === preferredTurn.dy);
    const altTurnMove = validMoves.find(m => m.dx === alternateTurn.dx && m.dy === alternateTurn.dy);
    const forwardMove = validMoves.find(m => m.dx === lastDir.dx && m.dy === lastDir.dy);

    let chosenMove: MonsterMoveStep;
    let selectedTurn: MonsterPatrolMoveResult['selectedTurn'] = 'none';

    if (preferTurnMove) {
        chosenMove = preferTurnMove;
        selectedTurn = 'preferred';
    } else if (forwardMove) {
        chosenMove = forwardMove;
        selectedTurn = 'forward';
    } else if (altTurnMove) {
        chosenMove = altTurnMove;
        selectedTurn = 'alternate';
    } else {
        chosenMove = validMoves[(getMonsterMoveSeed(monsterId, buildingId) + fallbackStepOffset) % validMoves.length];
        selectedTurn = 'random';
    }

    if (previousPos && chosenMove.x === previousPos.x && chosenMove.y === previousPos.y && validMoves.length > 1) {
        const altMove = validMoves.find(m => m.x !== previousPos.x || m.y !== previousPos.y);
        if (altMove) chosenMove = altMove;
    }

    return { chosenMove, selectedTurn };
}

function getMonsterZoneId(monster: Pick<PlacedBuilding, 'x' | 'y' | 'zoneId'>): string {
    return monster.zoneId || getZoneId(monster.x, monster.y);
}

function buildMonsterZoneCounts(buildings: PlacedBuilding[], buildingData: Building[]): Map<string, number> {
    const counts = new Map<string, number>();
    buildings.forEach((building) => {
        const info = buildingData.find(i => i.id === building.buildingId);
        if (!info || !info.stats.isMonster) return;
        if (building.isConstructing || building.isDestroying) return;
        if (building.hp !== undefined && building.hp <= 0) return;
        const zoneId = getMonsterZoneId(building);
        counts.set(zoneId, (counts.get(zoneId) || 0) + 1);
    });
    return counts;
}

function getCrowdingEscapeMove(
    monster: Pick<PlacedBuilding, 'x' | 'y' | 'zoneId'>,
    validMoves: MonsterMoveStep[],
    zoneCounts: Map<string, number>,
    isWrappedWorld: boolean
): MonsterMoveStep | null {
    if (validMoves.length === 0) return null;

    const currentZoneId = getMonsterZoneId(monster);
    const currentCount = zoneCounts.get(currentZoneId) || 0;
    if (currentCount < WILD_MONSTER_CROWDING_SOFT_CAP) return null;

    const zoneX = Math.floor(monster.x / ZONE_SIZE);
    const zoneY = Math.floor(monster.y / ZONE_SIZE);
    const localX = monster.x - (zoneX * ZONE_SIZE);
    const localY = monster.y - (zoneY * ZONE_SIZE);

    const neighborChecks = [
        { dx: -1, dy: 0, zoneX: zoneX - 1, zoneY, borderDist: localX },
        { dx: 1, dy: 0, zoneX: zoneX + 1, zoneY, borderDist: ZONE_SIZE - 1 - localX },
        { dx: 0, dy: -1, zoneX, zoneY: zoneY - 1, borderDist: localY },
        { dx: 0, dy: 1, zoneX, zoneY: zoneY + 1, borderDist: ZONE_SIZE - 1 - localY }
    ].filter(({ zoneX: nx, zoneY: ny }) =>
        isWrappedWorld || (nx >= 0 && nx < ZONES_X && ny >= 0 && ny < ZONES_Y)
    );

    let bestDirection: MonsterDirection | null = null;
    let bestScore = -Infinity;
    const pressureMultiplier = currentCount >= WILD_MONSTER_CROWDING_HARD_CAP ? 2 : 1;

    neighborChecks.forEach(({ dx, dy, zoneX: nx, zoneY: ny, borderDist }) => {
        const wrappedX = isWrappedWorld ? wrapCoord(nx, ZONES_X) : nx;
        const wrappedY = isWrappedWorld ? wrapCoord(ny, ZONES_Y) : ny;
        const neighborZoneId = `${wrappedX}_${wrappedY}`;
        const neighborCount = zoneCounts.get(neighborZoneId) || 0;
        const scarcityScore = currentCount - neighborCount;
        const borderBonus = Math.max(0, ZONE_SIZE - borderDist);
        const score = scarcityScore * 100 * pressureMultiplier + borderBonus;
        if (score > bestScore) {
            bestScore = score;
            bestDirection = { dx, dy };
        }
    });

    if (!bestDirection) return null;

    const preferredMove = validMoves.find(move => move.dx === bestDirection!.dx && move.dy === bestDirection!.dy);
    if (preferredMove) return preferredMove;

    let fallbackMove: MonsterMoveStep | null = null;
    let fallbackScore = -Infinity;
    validMoves.forEach(move => {
        const moveZoneId = getZoneId(move.x, move.y);
        const moveZoneCount = zoneCounts.get(moveZoneId) || 0;
        const score = -moveZoneCount * 100 - (moveZoneId === currentZoneId ? 25 : 0);
        if (score > fallbackScore) {
            fallbackScore = score;
            fallbackMove = move;
        }
    });
    return fallbackMove;
}

function isMonsterTileBlocked(
    x: number,
    y: number,
    occupiedPositions: Set<string>,
    blockedResourcePositions: Set<string>,
    extraBlocked?: (x: number, y: number) => boolean,
    isWrappedWorld = false
): boolean {
    const normalizedX = normalizeWorldCoord(x, WORLD_WIDTH_TILES, isWrappedWorld);
    const normalizedY = normalizeWorldCoord(y, WORLD_HEIGHT_TILES, isWrappedWorld);
    if (!isWrappedWorld && (normalizedX < 0 || normalizedX >= WORLD_WIDTH_TILES || normalizedY < 0 || normalizedY >= WORLD_HEIGHT_TILES)) {
        return true;
    }

    const key = `${normalizedX},${normalizedY}`;
    if (occupiedPositions.has(key)) return true;
    if (blockedResourcePositions.has(key)) return true;
    return extraBlocked ? extraBlocked(normalizedX, normalizedY) : false;
}

function findFreeMonsterTeleportSpot(
    monster: Pick<PlacedBuilding, 'x' | 'y' | 'zoneId'>,
    occupiedPositions: Set<string>,
    blockedResourcePositions: Set<string>,
    extraBlocked?: (x: number, y: number) => boolean
): MonsterTeleportSpot | null {
    const zoneId = monster.zoneId || getZoneId(monster.x, monster.y);
    const zoneParts = zoneId.split('_');
    const zX = Number.parseInt(zoneParts[0] || '0', 10);
    const zY = Number.parseInt(zoneParts[1] || '0', 10);
    const currentKey = `${monster.x},${monster.y}`;
    const isFreeSpot = (x: number, y: number) => {
        const key = `${x},${y}`;
        return key !== currentKey && !isMonsterTileBlocked(x, y, occupiedPositions, blockedResourcePositions, extraBlocked);
    };

    const tryZone = (zoneX: number, zoneY: number, maxTries: number): MonsterTeleportSpot | null => {
        if (zoneX < 0 || zoneX >= ZONES_X || zoneY < 0 || zoneY >= ZONES_Y) return null;
        const zoneStartX = zoneX * ZONE_SIZE;
        const zoneStartY = zoneY * ZONE_SIZE;
        for (let tries = 0; tries < maxTries; tries++) {
            const tx = zoneStartX + Math.floor(Math.random() * ZONE_SIZE);
            const ty = zoneStartY + Math.floor(Math.random() * ZONE_SIZE);
            if (isFreeSpot(tx, ty)) {
                return { x: tx, y: ty, zoneId: getZoneId(tx, ty) };
            }
        }
        return null;
    };

    const currentZoneSpot = tryZone(zX, zY, 300);
    if (currentZoneSpot) return currentZoneSpot;

    const neighborZones = [
        { x: zX - 1, y: zY },
        { x: zX + 1, y: zY },
        { x: zX, y: zY - 1 },
        { x: zX, y: zY + 1 },
        { x: zX - 1, y: zY - 1 },
        { x: zX + 1, y: zY + 1 },
        { x: zX - 1, y: zY + 1 },
        { x: zX + 1, y: zY - 1 }
    ];

    for (const zone of neighborZones) {
        const spot = tryZone(zone.x, zone.y, 200);
        if (spot) return spot;
    }

    return null;
}

function chooseMonsterBackgroundMove(
    monster: Pick<PlacedBuilding, 'id' | 'ownerId' | 'buildingId' | 'x' | 'y' | 'zoneId'>,
    buildings: PlacedBuilding[],
    buildingData: Building[],
    occupiedPositions: Set<string>,
    blockedResourcePositions: Set<string>,
    zoneCounts: Map<string, number>,
    isWrappedWorld: boolean,
    previousPos?: { x: number; y: number },
    lastDir?: MonsterDirection,
    recentPositions?: Array<{ x: number; y: number }>
): { chosenMove: MonsterMoveStep | null; nextDir: MonsterDirection } {
    const nextDir = lastDir || getMonsterPatrolDirection(monster.id, monster.buildingId);
    const adjacentHoldTarget = getMonsterAdjacentHoldTarget(monster, buildings, buildingData, { isWrappedWorld });
    if (adjacentHoldTarget) {
        return {
            chosenMove: null,
            nextDir: getWrappedDirectionToTarget(monster, adjacentHoldTarget, isWrappedWorld)
        };
    }

    const neighbors: MonsterMoveStep[] = getCardinalNeighborTiles(monster.x, monster.y, isWrappedWorld);

    const validMoves = neighbors.filter(move =>
        !isMonsterTileBlocked(move.x, move.y, occupiedPositions, blockedResourcePositions, undefined, isWrappedWorld)
    );
    if (validMoves.length === 0) {
        return { chosenMove: null, nextDir };
    }
    const recentKeys = new Set((recentPositions || []).map(pos => `${pos.x},${pos.y}`));
    const preferredMoves = validMoves.filter(move => !recentKeys.has(`${move.x},${move.y}`));
    const candidateMoves = preferredMoves.length > 0 ? preferredMoves : validMoves;

    const chaseTarget = getMonsterChaseTarget(monster, buildings, buildingData, { isWrappedWorld });
    let chosenMove: MonsterMoveStep | null = null;
    if (chaseTarget) {
        chosenMove = chooseMonsterMoveTowardTarget(candidateMoves, chaseTarget, isWrappedWorld);
    } else {
        chosenMove = getCrowdingEscapeMove(monster, candidateMoves, zoneCounts, isWrappedWorld);
        if (!chosenMove) {
            chosenMove = chooseMonsterPatrolMove(
                candidateMoves,
                nextDir,
                true,
                monster.id,
                monster.buildingId,
                0,
                previousPos
            ).chosenMove;
        }
    }

    if (chosenMove && previousPos && chosenMove.x === previousPos.x && chosenMove.y === previousPos.y && candidateMoves.length > 1) {
        const altMove = candidateMoves.find(m => m.x !== previousPos.x || m.y !== previousPos.y);
        if (altMove) chosenMove = altMove;
    }

    return {
        chosenMove,
        nextDir: chosenMove ? { dx: chosenMove.dx, dy: chosenMove.dy } : nextDir
    };
}

const normalizePlacedBuildingHealth = (building: PlacedBuilding): PlacedBuilding => {
    if (building.hp === undefined && building.maxHp === undefined) return building;

    const durabilityHint = building.maxHp ?? building.hp;
    let resolvedBuildingId = Number(building.buildingId);

    if (resolvedBuildingId === 619 && durabilityHint === 7376) {
        resolvedBuildingId = 636;
    } else if (resolvedBuildingId === 6201 && durabilityHint === 3328) {
        resolvedBuildingId = 6200;
    }

    const info = buildingData.find(i => i.id === resolvedBuildingId);
    if (!info || info.id === MOUNTAIN_ID || info.id === RIVER_ID) {
        return resolvedBuildingId === Number(building.buildingId)
            ? building
            : { ...building, buildingId: resolvedBuildingId };
    }

    const normalizedMaxHp = info.stats.durability;
    // Guard: if durability is undefined for this building type, we can't normalize HP.
    // Return as-is to avoid producing NaN values that corrupt the health system.
    if (normalizedMaxHp === undefined) return building;

    // CRITICAL FIX: Detect PocketBase schema migration artifact.
    // When hp/maxHp fields were added to the schema with default=0, all existing records
    // had their top-level hp=0 and maxHp=0. In a healthy game, killed buildings are
    // IMMEDIATELY deleted from the DB, so hp=0/maxHp=0 in a DB record is ALWAYS
    // a migration artifact Р Р†Р вЂљРІР‚Сњ never a legitimately dead building.
    // Legitimately dead buildings (killed by damage) have maxHp = positive durability
    // (set by a prior normalization call) while hp <= 0.
    // IMPORTANT: treat only maxHp=0 as migration artifact.
    // maxHp=undefined can happen in legit destruction pipelines right before delete,
    // and restoring such records to full HP causes "respawn after explosion".
    const now = Date.now();
    const hasPendingTerminalState = Boolean(
        building.isDestroying ||
        hasActiveDestructionWindow(building.destructionEndTime, now) ||
        ((building.pendingDamage || 0) > 0)
    );
    if (building.hp === 0 && building.maxHp === 0 && !hasPendingTerminalState) {
        return {
            ...building,
            buildingId: resolvedBuildingId,
            hp: normalizedMaxHp,
            maxHp: normalizedMaxHp
        };
    }

    const rawHp = typeof building.hp === 'number' && Number.isFinite(building.hp)
        ? building.hp
        : normalizedMaxHp;
    const normalizedHp = Math.max(0, Math.min(rawHp, normalizedMaxHp));

    if (
        Number(building.buildingId) === resolvedBuildingId &&
        building.maxHp === normalizedMaxHp &&
        building.hp === normalizedHp &&
        (!BANDIT_CASTLE_IDS.has(resolvedBuildingId) || (!building.workState && !building.workEndTime))
    ) {
        return building;
    }

    const shouldClearBanditCastleWorkState = BANDIT_CASTLE_IDS.has(resolvedBuildingId);

    return {
        ...building,
        buildingId: resolvedBuildingId,
        hp: normalizedHp,
        maxHp: normalizedMaxHp,
        ...(shouldClearBanditCastleWorkState ? { workState: undefined, workEndTime: undefined } : {})
    };
};

const isBuildingAlive = (building: Pick<PlacedBuilding, 'hp'>): boolean =>
    building.hp === undefined || building.hp > 0;

