    const enqueueImagePreload = useCallback((
        urls: string[],
        options?: { batchSize?: number; delayMs?: number; onComplete?: () => void }
    ) => {
        const requestedUrls = [...new Set((urls || []).filter(Boolean))];
        const batchSize = options?.batchSize ?? 20;

        const startLoading = () => {
            const urlsToLoad = requestedUrls.filter((url) => {
                const normalizedUrl = normalizeAssetUrl(url);
                return (
                    !loadedImageElementsRef.current[url] &&
                    !loadedImageElementsRef.current[normalizedUrl] &&
                    !requestedImageUrlsRef.current.has(url) &&
                    !requestedImageUrlsRef.current.has(normalizedUrl)
                );
            });

            if (urlsToLoad.length === 0) {
                options?.onComplete?.();
                return;
            }

            let completed = 0;
            let pendingBatch: Record<string, HTMLImageElement> = {};

            const flushBatch = () => {
                if (Object.keys(pendingBatch).length === 0) return;
                const batch = pendingBatch;
                pendingBatch = {};
                setImages(prev => ({ ...prev, ...batch }));
            };

            urlsToLoad.forEach(url => {
                const normalizedUrl = normalizeAssetUrl(url);
                requestedImageUrlsRef.current.add(url);
                requestedImageUrlsRef.current.add(normalizedUrl);

                let finished = false;
                let attempts = 0;
                const maxAttempts = 3;

                const finish = () => {
                    if (finished) return;
                    finished = true;
                    completed++;
                    if (completed % batchSize === 0 || completed === urlsToLoad.length) {
                        flushBatch();
                    }
                    if (completed === urlsToLoad.length) {
                        options?.onComplete?.();
                    }
                };

                const tryLoad = () => {
                    attempts++;
                    const img = new Image();
                    img.onload = () => {
                        loadedImageElementsRef.current[url] = img;
                        loadedImageElementsRef.current[normalizedUrl] = img;
                        pendingBatch[url] = img;
                        pendingBatch[normalizedUrl] = img;
                        finish();
                    };
                    img.onerror = () => {
                        if (attempts < maxAttempts) {
                            const backoffMs = 250 * attempts;
                            window.setTimeout(tryLoad, backoffMs);
                            return;
                        }
                        requestedImageUrlsRef.current.delete(url);
                        requestedImageUrlsRef.current.delete(normalizedUrl);
                        finish();
                    };
                    img.src = normalizedUrl;
                };

                tryLoad();
            });
        };

        if (options?.delayMs) {
            window.setTimeout(startLoading, options.delayMs);
        } else {
            startLoading();
        }
    }, []);

