    const deletingBuildingsRef = useRef<Map<string, number>>(new Map());
    // Set of building IDs confirmed deleted by server (no longer present in any snapshot)
    const confirmedDeletedRef = useRef<Set<string>>(new Set());
    const DELETION_PROTECTION_MS = 120000; // Keep deleted IDs for 2 minutes (was 30s - too short for laggy connections)

    // Helper to check if building is being deleted (with auto-cleanup)
    const isBuildingDeleting = useCallback((id: string): boolean => {
        const deleteTime = deletingBuildingsRef.current.get(id);
        if (!deleteTime) return false;
        
        // Keep blocking stale snapshots for a short window even after server-confirmed deletion.
        // This prevents "resurrection" when a late snapshot still contains old data.
        if (Date.now() - deleteTime > DELETION_PROTECTION_MS) {
            deletingBuildingsRef.current.delete(id);
            confirmedDeletedRef.current.delete(id);
            return false;
        }
        return true;
    }, []);
    const isBuildingTombstoned = useCallback((id: string): boolean => {
        if (isBuildingDeleting(id)) return true;
        if (!confirmedDeletedRef.current.has(id)) return false;
        const deleteTime = deletingBuildingsRef.current.get(id);
        if (!deleteTime) {
            confirmedDeletedRef.current.delete(id);
            return false;
        }
        if (Date.now() - deleteTime > DELETION_PROTECTION_MS) {
            deletingBuildingsRef.current.delete(id);
            confirmedDeletedRef.current.delete(id);
            return false;
        }
        return true;
    }, [isBuildingDeleting]);
