    // Handle redundant Town Halls cleanup
    useEffect(() => {
        if (!isAuthReady || !user || !placedBuildings.length) return;

        // Find all Town Halls owned by me (exclude dead ones: hp=0 means already destroyed)
        const myTownHalls = placedBuildings
            .filter(b => TOWN_HALL_IDS.includes(Number(b.buildingId)) && isMyBuilding(b)
                      && (b.hp === undefined || b.hp > 0))
            .sort((a, b) => {
                // Sort by constructionEndTime ascending (oldest first)
                const timeA = a.constructionEndTime || a.timestamp || 0;
                const timeB = b.constructionEndTime || b.timestamp || 0;
                return timeA - timeB; // Oldest first
            });

        // Track first seen times only for current TH ids to enforce a stabilization window
        const now = Date.now();
        const currentIds = new Set(myTownHalls.map(b => String(b.id)));
        townHallCleanupFirstSeenRef.current.forEach((_, id) => {
            if (!currentIds.has(id)) townHallCleanupFirstSeenRef.current.delete(id);
        });
        myTownHalls.forEach(b => {
            const id = String(b.id);
            if (!townHallCleanupFirstSeenRef.current.has(id)) {
                townHallCleanupFirstSeenRef.current.set(id, now);
            }
        });

        if (myTownHalls.length > 1) {
            if (shouldLogTownHallEvent(`cleanup-duplicates-${playerName}`, 30000)) {
                console.warn(`[TH-CLEANUP] Detected ${myTownHalls.length} Town Halls for ${playerName}; running safe duplicate cleanup.`);
            }
            // Never cleanup while any TH is still local/constructing/deleting.
            // This prevents killing a just-placed Town Hall during optimistic sync.
            const hasUnstableTownHall = myTownHalls.some(b =>
                b.isLocal || b.isConstructing || isBuildingDeleting(String(b.id))
            );
            if (hasUnstableTownHall) return;

            // Stabilization window: wait until each TH has remained visible for at least 30s.
            // This protects against transient duplicates during map/server reconciliation.
            const hasNotSettled = myTownHalls.some(b => {
                const firstSeen = townHallCleanupFirstSeenRef.current.get(String(b.id)) || now;
                return (now - firstSeen) < 30000;
            });
            if (hasNotSettled) return;

            // Skip cleanup if any Town Hall was recently completed (<30s).
            const hasVeryNewCompletion = myTownHalls.some(b => {
                const endTime = b.constructionEndTime || 0;
                return endTime > 0 && (now - endTime) < 30000;
            });
            if (hasVeryNewCompletion) return; // Wait for state to settle

            // Keep the first (oldest) one, delete others
            const duplicates = myTownHalls.slice(1);
            console.log(`?? [CLEANUP] Found ${duplicates.length} duplicate Town Halls for player ${playerName}. Keeping oldest, deleting others.`);

            duplicates.forEach(async (dup) => {
                try {
                    const docId = String(dup.id);
                    // Mark as deleted locally immediately so the duplicate cannot linger or resurrect.
                    removeBuildingFromSnapshotCaches(docId);
                    setPlacedBuildings(prev => prev.filter(b => String(b.id) !== docId));
                    setSelectedBuilding(prev => prev && String(prev.building.id) === docId ? null : prev);

                    // Delete from DB
                    await deleteDoc(doc(db, 'buildings', docId));
                    addHistoryLog(`Дубликат Городского центра автоматически удален.`, 'system');
                    console.log(`Р Р†РЎС™РІР‚В¦ [CLEANUP] Deleted redundant Town Hall: ${docId}`);
                } catch (error) {
                    console.error(`Р Р†РЎСљР Р‰ [CLEANUP] Failed to delete duplicate Town Hall ${dup.id}:`, error);
                }
            });
        }
    }, [placedBuildings, user, isAuthReady, isMyBuilding, playerName, shouldLogTownHallEvent, removeBuildingFromSnapshotCaches]);


