            deleteDoc(doc(db, 'map_resources', `${selectedOilDeposit.x}_${selectedOilDeposit.y}`)).catch(e => handleFirestoreError(e, OperationType.DELETE, `map_resources/${selectedOilDeposit.x}_${selectedOilDeposit.y}`));
