    const handleBuyRuby = () => {
        if (isShopProcessing) return;
        const totalCost = buyRubyAmount * 10000;

        if (isAuthReady && user) {
            setIsShopProcessing(true);
            const userRef = doc(db, 'users', user.uid);

            runTransaction(db, async (transaction) => {
                const userDoc = await transaction.get(userRef);
                if (!userDoc.exists()) throw new Error("User not found");

                const currentGold = Number(userDoc.data().gold) || 0;
                if (currentGold < totalCost) throw new Error("Insufficient gold");

                const currentRubies = Number(userDoc.data().rubies) || 0;

                transaction.update(userRef, {
                    gold: currentGold - totalCost,
                    rubies: currentRubies + buyRubyAmount
                });
            })
                .then(() => {
                    addHistoryLog(`Куплено ${buyRubyAmount} рубинов за ${totalCost.toLocaleString()} монет.`, 'economy');
                })
                .catch(e => {
                    console.error("Buy ruby failed: ", e);
                    if (e.message === "Insufficient gold") {
                        alert("Недостаточно золота!");
                    } else {
                        handleFirestoreError(e, OperationType.UPDATE, `users/${user.uid}`);
                    }
                })
                .finally(() => setIsShopProcessing(false));
        } else {
            if (playerGold >= totalCost) {
                updatePlayerResources(-totalCost, buyRubyAmount, {});
                addHistoryLog(`Куплено ${buyRubyAmount} рубинов за ${totalCost.toLocaleString()} монет.`, 'economy');
            } else {
                alert("Недостаточно золота!");
            }
        }
    };

    const handleBuyShopItem = (item: Item, quantity: number = 1) => {
        if (isShopProcessing) return;
        if (!item.rubyPackQuantity) return;
        if (quantity < 1) return;

        if (isAuthReady && user) {
            setIsShopProcessing(true);
            const userRef = doc(db, 'users', user.uid);

            runTransaction(db, async (transaction) => {
                const userDoc = await transaction.get(userRef);
                if (!userDoc.exists()) throw new Error("User not found");

                const currentRubies = Number(userDoc.data().rubies) || 0;
                if (currentRubies < quantity) throw new Error("Insufficient rubies");

                const currentItemAmount = Number(userDoc.data().inventory?.[item.id]) || 0;

                transaction.update(userRef, {
                    rubies: currentRubies - quantity,
                    [`inventory.${item.id}`]: currentItemAmount + (item.rubyPackQuantity! * quantity)
                });
            })
                .then(() => {
                    addHistoryLog(`Куплено ${item.rubyPackQuantity! * quantity} ${item.name} за ${quantity} рубинов.`, 'economy');
                })
                .catch(e => {
                    console.error("Buy shop item failed: ", e);
                    if (e.message === "Insufficient rubies") {
                        openRubyWarningModal(quantity);
                    } else {
                        handleFirestoreError(e, OperationType.UPDATE, `users/${user.uid}`);
                    }
                })
                .finally(() => setIsShopProcessing(false));
        } else {
            if (playerRubies >= quantity) {
                updatePlayerResources(0, -quantity, { [item.id]: item.rubyPackQuantity! * quantity });
                addHistoryLog(`Куплено ${item.rubyPackQuantity! * quantity} ${item.name} за ${quantity} рубинов.`, 'economy');
            } else {
                openRubyWarningModal(quantity);
            }
        }
    };

