    const handleRubyExchange = () => {
        if (isShopProcessing) return;
        if (exchangeAmount <= 0) return;
        const coins = exchangeAmount * 7777;

        if (isAuthReady && user) {
            setIsShopProcessing(true);
            const userRef = doc(db, 'users', user.uid);

            runTransaction(db, async (transaction) => {
                const userDoc = await transaction.get(userRef);
                if (!userDoc.exists()) throw new Error("User not found");

                const currentRubies = Number(userDoc.data().rubies) || 0;
                if (currentRubies < exchangeAmount) throw new Error("Insufficient rubies");

                const currentGold = Number(userDoc.data().gold) || 0;
                const newGold = Math.min(goldCapacity, currentGold + coins);

                transaction.update(userRef, {
                    rubies: currentRubies - exchangeAmount,
                    gold: newGold
                });
            })
                .then(() => {
                    setShowExchangeModal(false);
                    setExchangeAmount(1);
                    addHistoryLog(`Обменяно ${exchangeAmount} рубинов на ${coins} монет.`, 'economy');
                    alert(`Р С›Р В±Р СР ВµР Р… РЎС“РЎРѓР С—Р ВµРЎв‚¬Р ВµР Р…! Вы Р С—Р С•Р В»РЎС“РЎвЂЎР С‘Р В»Р С‘ ${coins.toLocaleString()} Р СР С•Р Р…Р ВµРЎвЂљ.`);
                })
                .catch(e => {
                    console.error("Ruby exchange failed: ", e);
                    if (e.message === "Insufficient rubies") {
                        openRubyWarningModal(exchangeAmount);
                    } else {
                        handleFirestoreError(e, OperationType.UPDATE, `users/${user.uid}`);
                    }
                })
                .finally(() => setIsShopProcessing(false));
        } else {
            if (playerRubies >= exchangeAmount) {
                updatePlayerResources(coins, -exchangeAmount, {});
                setShowExchangeModal(false);
                setExchangeAmount(1);
                addHistoryLog(`Обменяно ${exchangeAmount} рубинов на ${coins} монет.`, 'economy');
                alert(`Р С›Р В±Р СР ВµР Р… РЎС“РЎРѓР С—Р ВµРЎв‚¬Р ВµР Р…! Вы Р С—Р С•Р В»РЎС“РЎвЂЎР С‘Р В»Р С‘ ${coins.toLocaleString()} Р СР С•Р Р…Р ВµРЎвЂљ.`);
            } else {
                openRubyWarningModal(exchangeAmount);
            }
        }
    };

    // Casino gambling function
    // Rules: Casino usually wins, but if bet > 10000 coins, there's a small chance to win a ruby
    // Approximately 1 ruby win per 20 bets, with ~15% variance on that chance
    const handleCasinoGamble = () => {
        if (casinoIsSpinning) return;
        if (casinoBetAmount <= 0) {
            alert("Ставка должна быть больше 0!");
            return;
        }
        if (playerGold < casinoBetAmount) {
            alert("Недостаточно монет для ставки!");
            return;
        }

        setCasinoIsSpinning(true);
        setCasinoResult(null);

        // Simulate spinning animation delay
        setTimeout(() => {
            const bet = casinoBetAmount;
            let won = false;
            let winAmount = 0;
            let isRuby = false;

            // Base win chance is around 40% (casino usually wins)
            const baseWinChance = 0.4;
            const random = Math.random();

            if (bet > 10000) {
                // For bets over 10000, there's a chance to win a ruby
                // ~1 win per 20 bets = 5% base chance, with 15% variance
                // So chance ranges from ~4.25% to ~5.75%
                const variance = 0.15;
                const rubyWinChance = 0.05 * (1 + (Math.random() * 2 - 1) * variance);
                
                if (random < rubyWinChance) {
                    // Won a ruby!
                    won = true;
                    winAmount = 1;
                    isRuby = true;
                } else if (random < rubyWinChance + baseWinChance) {
                    // Regular coin win
                    won = true;
                    winAmount = Math.floor(bet * 1.5); // Win 1.5x the bet
                    isRuby = false;
                }
            } else {
                // For bets <= 10000, only coin wins/losses
                if (random < baseWinChance) {
                    won = true;
                    winAmount = Math.floor(bet * 1.5);
                }
            }

            // Update player resources
            if (won) {
                if (isRuby) {
                    updatePlayerResources(-bet, winAmount, {});
                    addHistoryLog(`Казино: выигран рубин. Ставка: ${bet}.`, 'economy');
                } else {
                    const netWin = winAmount - bet;
                    updatePlayerResources(netWin, 0, {});
                    addHistoryLog(`Казино: выигрыш ${winAmount} монет. Ставка: ${bet}.`, 'economy');
                }
            } else {
                updatePlayerResources(-bet, 0, {});
                const casinoBankShare = Math.max(1, Math.floor(bet * 0.2));
                if (activeCasinoBuilding) {
                    const casinoBuildingId = String(activeCasinoBuilding.id);
                    setPlacedBuildings(prev => prev.map(b =>
                        String(b.id) === casinoBuildingId
                            ? { ...b, bank: (b.bank || 0) + casinoBankShare }
                            : b
                    ));
                    setActiveCasinoBuilding(prev => prev && String(prev.id) === casinoBuildingId
                        ? { ...prev, bank: (prev.bank || 0) + casinoBankShare }
                        : prev
                    );
                    if (isAuthReady && user) {
                        updateDoc(doc(db, 'buildings', casinoBuildingId), {
                            bank: increment(casinoBankShare)
                        }).catch(e => handleFirestoreError(e, OperationType.UPDATE, `buildings/${casinoBuildingId}`));
                    }
                }
                addHistoryLog(`Казино: проигрыш. Ставка: ${bet}. В банк казино ушло ${Math.max(1, Math.floor(bet * 0.2))} монет.`, 'economy');
            }

            setCasinoResult({ won, amount: winAmount, isRuby });
            setCasinoIsSpinning(false);
        }, 1500); // 1.5 second spin animation
    };

    const handleUpgrade = () => {
        if (!selectedBuilding) return;

        // Get fresh building data to avoid stale info
        const currentBuildingInfo = buildingData.find(b => b.id === selectedBuilding.building.buildingId);
        if (!currentBuildingInfo) return;

        const upgradeTargetId = currentBuildingInfo.upgradesTo;
        const cost = currentBuildingInfo.upgradeCost;
        const newBuildingInfo = buildingData.find(b => b.id === upgradeTargetId);

        if (!newBuildingInfo || cost === undefined) {
            alert("Р В­РЎвЂљР С• Р В·Р Т‘Р В°Р Р…Р С‘Р Вµ Р Р…Р ВµР В»РЎРЉР В·РЎРЏ РЎС“Р В»РЎС“РЎвЂЎРЎв‚¬Р С‘РЎвЂљРЎРЉ!");
            return;
        }

        if (playerGold < cost) {
            alert(`Недостаточно золота для улучшения! Требуется: ${cost} монет.`);
            return;
        }

        if (newBuildingInfo.constructionRequirements.population && newBuildingInfo.type !== BuildingType.TownHall) {
            const requiredPop = newBuildingInfo.constructionRequirements.population;
            const availablePop = maxPopulation - currentPopulation;
            if (availablePop < requiredPop) {
                alert(`Недостаточно населения для улучшения! Требуется: ${requiredPop}`);
                return;
            }
        }

        if (newBuildingInfo.constructionRequirements.resources) {
            const missingResources = newBuildingInfo.constructionRequirements.resources.filter(req => (inventory[req.id] || 0) < (req.amount || 0));
            if (missingResources.length > 0) {
                const missingNames = missingResources.map(r => `${r.name} (нужно: ${r.amount}, есть: ${inventory[r.id] || 0})`).join(', ');
                alert(`Недостаточно ресурсов для улучшения: ${missingNames}`);
                return;
            }
        }

        const inventoryDeltas: Record<number, number> = {};
        if (newBuildingInfo.constructionRequirements.resources) {
            newBuildingInfo.constructionRequirements.resources.forEach(req => {
                inventoryDeltas[req.id] = -(req.amount || 0);
            });
        }
        const upgradeStartedAt = Date.now();
        const upgradeConstructionEndTime = upgradeStartedAt + (newBuildingInfo.stats.constructionTimeSeconds || 0) * 1000;
        updatePlayerResources(-cost, 0, inventoryDeltas);

        setVisualEffects(prev => [...prev, createVisualEffect({
            id: Date.now(),
            x: selectedBuilding.building.x,
            y: selectedBuilding.building.y,
            type: 'upgrade',
            startTime: Date.now(),
            duration: UPGRADE_EFFECT_DURATION
        })]);

        addHistoryLog(`Улучшение здания "${selectedBuilding.info.name}" до "${newBuildingInfo.name}". Стоимость: ${cost} монет.`, 'build');

        // Optimistic update for all buildings (immediate UI feedback)
        lastInteractionRef.current.set(String(selectedBuilding.building.id), Date.now());
        if (RUNTIME_AUDIT_ENABLED) {
            recordBuildingTimerTrace('local-start', {
                ...selectedBuilding.building,
                buildingId: newBuildingInfo.id,
                isConstructing: true,
                constructionEndTime: upgradeConstructionEndTime,
                workState: 'idle',
                actionType: 'construction',
            }, {
                now: upgradeStartedAt,
                constructionStartTime: upgradeStartedAt,
                constructionEndTime: upgradeConstructionEndTime,
                sourceCode: 'handleUpgrade',
            });
        }
        setPlacedBuildings(prev => {
            const index = prev.findIndex(b => b.id === selectedBuilding.building.id);
            if (index === -1) return prev;

            const newBuildings = [...prev];
            newBuildings[index] = {
                ...newBuildings[index],
                buildingId: newBuildingInfo.id,
                isConstructing: true,
                constructionEndTime: upgradeConstructionEndTime,
                lastAttackTime: upgradeStartedAt,
                type: newBuildingInfo.type,
                hp: newBuildingInfo.stats.durability,
                maxHp: newBuildingInfo.stats.durability,
                isDestroying: false,
                destructionStartedAt: undefined,
                destructionEndTime: undefined,
                destructionExpiresAt: undefined,
                destructionDurationMs: undefined,
                destructionMaxLifetimeMs: undefined,
                destructionStatus: 'finished',
                pendingDamage: 0,
                initiatorId: undefined,
                isLocal: true // Mark as local optimistic update
            };
            return newBuildings;
        });

        if (isAuthReady && user) {
            const buildingDocId = String(selectedBuilding.building.id);
            updateDoc(doc(db, 'buildings', buildingDocId), {
                buildingId: newBuildingInfo.id,
                isConstructing: true,
                constructionEndTime: upgradeConstructionEndTime,
                lastAttackTime: upgradeStartedAt,
                type: newBuildingInfo.type || deleteField(),
                hp: newBuildingInfo.stats.durability,
                maxHp: newBuildingInfo.stats.durability,
                isDestroying: false,
                destructionStartedAt: deleteField(),
                destructionEndTime: deleteField(),
                destructionExpiresAt: deleteField(),
                destructionDurationMs: deleteField(),
                destructionMaxLifetimeMs: deleteField(),
                destructionStatus: 'finished',
                pendingDamage: 0,
                initiatorId: deleteField()
            }).catch(e => handleFirestoreError(e, OperationType.UPDATE, `buildings/${buildingDocId}`));
        } else {
            setPlacedBuildings(prev => {
                const index = prev.findIndex(b => b.x === selectedBuilding.building.x && b.y === selectedBuilding.building.y);
                if (index === -1) return prev;

                const newBuildings = [...prev];
                newBuildings[index] = {
                    ...newBuildings[index],
                    buildingId: newBuildingInfo.id,
                    isConstructing: true,
                    constructionEndTime: upgradeConstructionEndTime,
                    lastAttackTime: upgradeStartedAt,
                    type: newBuildingInfo.type,
                    hp: newBuildingInfo.stats.durability,
                    maxHp: newBuildingInfo.stats.durability,
                    isDestroying: false,
                    destructionStartedAt: undefined,
                    destructionEndTime: undefined,
                    destructionExpiresAt: undefined,
                    destructionDurationMs: undefined,
                    destructionMaxLifetimeMs: undefined,
                    destructionStatus: 'finished',
                    pendingDamage: 0,
                    initiatorId: undefined
                };
                return newBuildings;
            });
        }

        setSelectedBuilding(null);
    };

    const handleStartProductionFromWorld = (building: PlacedBuilding, info: Building) => {
        // Cannot start production while building is under construction or upgrading
        if (building.isConstructing) return;
        if (isBanditCastleBuildingId(building.buildingId)) return;

        const popCost = info.stats.takesPopulation || 0;
        if (currentPopulation + popCost > maxPopulation) {
            alert(`Недостаточно рабочих! Требуется: ${popCost}, Свободно: ${maxPopulation - currentPopulation}`);
            return;
        }

        if (info.stats.consumes) {
            for (const req of info.stats.consumes) {
                if ((inventory[req.id] || 0) < (req.amount || 0)) {
                    alert(`Недостаточно ресурса: ${getCanonicalItemName(req.id, req.name, building.id)}`);
                    return;
                }
            }
        }

        const inventoryDeltas: Record<number, number> = {};
        if (info.stats.consumes) {
            info.stats.consumes.forEach(req => {
                inventoryDeltas[req.id] = -(req.amount || 0);
            });
        }
        updatePlayerResources(0, 0, inventoryDeltas);

        const buildingDocId = String(building.id);
        const workStartedAt = Date.now();
        const workEndTime = workStartedAt + (info.stats.workTimeSeconds || 0) * 1000;

        // Always switch locally first so production starts instantly in UI.
        if (RUNTIME_AUDIT_ENABLED) {
            recordBuildingTimerTrace('local-start', {
                ...building,
                workState: 'working',
                workStartTime: workStartedAt,
                workEndTime,
                actionType: 'working',
            }, {
                now: workStartedAt,
                workStartTime: workStartedAt,
                workEndTime,
                sourceCode: 'handleStartProductionFromWorld',
            });
        }
        setPlacedBuildings(prev => prev.map(b =>
            b.id === building.id ? { ...b, workState: 'working', workEndTime, isLocal: true } : b
        ));
        lastInteractionRef.current.set(buildingDocId, Date.now());

        // Sync to backend when authenticated.
        if (isAuthReady && user) {
            updateDoc(doc(db, 'buildings', buildingDocId), {
                workState: 'working',
                workEndTime
            }).catch(e => handleFirestoreError(e, OperationType.UPDATE, `buildings/${buildingDocId}`));
        }
    };
