    const cleanupGhostBuildingsForCurrentUser = useCallback(async () => {
        const currentUser = userRef.current;
        if (!currentUser?.uid) return;

        try {
            const buildingsCol = collection(db, 'buildings');
            const myBuildingsQuery = query(buildingsCol, where('ownerId', '==', currentUser.uid));
            const snap = await getDocs(myBuildingsQuery);

            const rows: Array<{ docId: string; b: PlacedBuilding }> = [];
            snap.forEach((d) => {
                rows.push({ docId: d.id, b: { ...(d.data() as PlacedBuilding), id: d.id } as PlacedBuilding });
            });

            const toDelete = new Set<string>();

            for (const row of rows) {
                const b = row.b;
                const hasInvalidCoords = !Number.isFinite(b.x) || !Number.isFinite(b.y);
                const isDead = !isBuildingAlive(b);
                if (hasInvalidCoords || isDead) {
                    toDelete.add(row.docId);
                }
            }

            // Keep only one Town Hall (the newest valid one), remove stale extras.
            const validTownHalls = rows
                .filter(row =>
                    !toDelete.has(row.docId) &&
                    TOWN_HALL_IDS.includes(Number(row.b.buildingId)) &&
                    isBuildingAlive(row.b)
                )
                .sort((a, b) => (Number(b.b.timestamp || 0) - Number(a.b.timestamp || 0)));
            for (let i = 1; i < validTownHalls.length; i++) {
                toDelete.add(validTownHalls[i].docId);
            }

            // Remove exact duplicates: same tile + same buildingId, keep newest.
            const dupGroups = new Map<string, Array<{ docId: string; b: PlacedBuilding }>>();
            for (const row of rows) {
                if (toDelete.has(row.docId)) continue;
                const key = `${row.b.buildingId}:${row.b.x}:${row.b.y}`;
                const arr = dupGroups.get(key) || [];
                arr.push(row);
                dupGroups.set(key, arr);
            }
            dupGroups.forEach((arr) => {
                if (arr.length <= 1) return;
                arr.sort((a, b) => (Number(b.b.timestamp || 0) - Number(a.b.timestamp || 0)));
                for (let i = 1; i < arr.length; i++) {
                    toDelete.add(arr[i].docId);
                }
            });

            if (toDelete.size === 0) return;

            await Promise.all(
                Array.from(toDelete).map((docId) =>
                    {
                        removeBuildingFromSnapshotCaches(docId);
                        return deleteDoc(doc(db, 'buildings', docId)).catch((e) => {
                            handleFirestoreError(e, OperationType.DELETE, `buildings/${docId}`);
                        });
                    }
                )
            );

            setPlacedBuildings(prev => prev.filter(b => !toDelete.has(String(b.id))));
            setSelectedBuilding(prev => prev && toDelete.has(String(prev.building.id)) ? null : prev);

            console.log(`[GhostCleanup] Removed ${toDelete.size} ghost building(s) for user ${currentUser.uid}`);
        } catch (e) {
            console.warn('[GhostCleanup] Failed to cleanup ghost buildings:', e);
        }
    }, [db]);

