                if (giftSubTab === 'main' && (giftSubCategory === 'castles' || giftSubCategory === 'babies' || giftSubCategory === 'march8' || giftSubCategory === 'halloween' || giftSubCategory === 'valentine' || giftSubCategory === 'spring')) return false;
