                                    const col = index % ZONES_X;

                                    const hasTownHall = townHallLocation &&
                                        Math.floor(townHallLocation.x / ZONE_SIZE) === col &&
                                        Math.floor(townHallLocation.y / ZONE_SIZE) === row;

